from collections import defaultdict

class Solution(object):
    def countBlackBlocks(self, m, n, coordinates):
        # A 2x2 block is identified by its top-left corner (r, c)
        # where 0 <= r < m-1 and 0 <= c < n-1
        # Black cell (x, y) belongs to blocks with top-left at:
        # (x-1, y-1), (x-1, y), (x, y-1), (x, y)
        block_count = defaultdict(int)
        black = set(map(tuple, coordinates))

        for x, y in coordinates:
            for br in [x - 1, x]:
                for bc in [y - 1, y]:
                    if 0 <= br < m - 1 and 0 <= bc < n - 1:
                        block_count[(br, bc)] += 1

        ans = [0] * 5
        for v in block_count.values():
            ans[v] += 1
        # Blocks with 0 black cells = total blocks - blocks with >= 1 black cell
        total_blocks = (m - 1) * (n - 1)
        ans[0] = total_blocks - len(block_count)
        return ans
